// ── UTILS ─────────────────────────────────────────────────────
const imc    = (p, h) => (p / (h/100)**2).toFixed(1);
const imcCor = v => { v=parseFloat(v); return v<25?"#4CAF50":v<30?"#FF9800":v<35?"#FF5722":"#F44336"; };
const imcTxt = v => { v=parseFloat(v); return v<18.5?"Abaixo":v<25?"Normal":v<30?"Sobrepeso":v<35?"Obesidade I":v<40?"Obesidade II":"Obesidade III"; };
const pct    = (c,s,g) => Math.min(100, Math.max(0, ((s-c)/(s-g)*100)));
const rnd    = a => a[Math.floor(Math.random()*a.length)];
const hoje   = () => new Date().toLocaleDateString("pt-BR",{weekday:"long",day:"2-digit",month:"long"});
const DIAS   = ["Dom","Seg","Ter","Qua","Qui","Sex","Sáb"];
const CHAVE_TREINOS = ["A","B","C","D","E"];
const DIAS_TREINO   = [null,0,1,2,3,null,4];
